import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import {
  ShoppingBag,
  Search,
  User,
  Heart,
  Menu,
  LogOut,
  LayoutDashboard,
  Settings,
  ChevronDown,
  X
} from 'lucide-react';

const Navbar = () => {
  const { user, cartCount, logout, t } = useApp();
  const navigate = useNavigate();
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);
  const [showMobileMenu, setShowMobileMenu] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setShowDropdown(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Close dropdown on route change
  useEffect(() => {
    setShowDropdown(false);
    setShowMobileMenu(false);
  }, [location.pathname]);

  const handleLogout = () => {
    logout();
    navigate('/');
    setShowDropdown(false);
  };

  const isActive = (path) => location.pathname === path;

  const avatarLetter = user ? (user.username || 'U').charAt(0).toUpperCase() : 'U';
  const avatarColors = ['#2563EB', '#7C3AED', '#DB2777', '#059669', '#D97706'];
  const avatarColor = user ? (avatarColors[user.id % avatarColors.length] || '#2563EB') : '#2563EB';

  return (
    <>
      <nav className={`navbar ${isScrolled ? 'scrolled' : ''}`}>
        <div className="container nav-container">
          <Link to="/" className="nav-logo">
            <ShoppingBag size={28} strokeWidth={2.5} />
            <span>ShopSRY</span>
          </Link>

          <div className="nav-menu">
            <Link to="/" className={`nav-link ${isActive('/') ? 'active' : ''}`}>{t.home}</Link>
            <Link to="/products" className={`nav-link ${isActive('/products') ? 'active' : ''}`}>{t.shop}</Link>
            <Link to="/#categories" className="nav-link">{t.categories}</Link>
            <Link to="/#about" className="nav-link">{t.about}</Link>
            <Link to="/#contact" className="nav-link">{t.contact}</Link>
          </div>

          <div className="nav-actions">
            <div className="search-bar">
              <Search className="search-bar-icon" size={18} />
              <input type="text" placeholder={t.search} />
            </div>

            <Link to="/wishlist" className="nav-btn">
              <Heart size={22} />
            </Link>

            <Link to="/cart" className="nav-btn">
              <ShoppingBag size={22} />
              {cartCount > 0 && <span className="badge">{cartCount}</span>}
            </Link>

            {user ? (
              <div className="profile-dropdown-wrap" ref={dropdownRef}>
                <button
                  className="profile-avatar-btn"
                  onClick={() => setShowDropdown(!showDropdown)}
                  style={{ background: avatarColor }}
                >
                  {avatarLetter}
                  <ChevronDown size={14} className={`dropdown-arrow ${showDropdown ? 'open' : ''}`} />
                </button>

                {showDropdown && (
                  <div className="profile-dropdown">
                    <div className="dropdown-user-info">
                      <div className="dropdown-avatar" style={{ background: avatarColor }}>
                        {avatarLetter}
                      </div>
                      <div>
                        <span className="dropdown-name">{user.username}</span>
                        <span className="dropdown-email">{user.email}</span>
                      </div>
                    </div>

                    <div className="dropdown-divider" />

                    <Link to="/profile" className="dropdown-item">
                      <User size={16} />
                      {t.profile}
                    </Link>

                    <Link to="/orders" className="dropdown-item">
                      <ShoppingBag size={16} />
                      {t.myOrders}
                    </Link>

                    <Link to="/settings" className="dropdown-item">
                      <Settings size={16} />
                      {t.settings}
                    </Link>

                    {user.role === 'admin' && (
                      <>
                        <div className="dropdown-divider" />
                        <Link to="/admin" className="dropdown-item admin-item">
                          <LayoutDashboard size={16} />
                          {t.adminPanel}
                        </Link>
                      </>
                    )}

                    <div className="dropdown-divider" />

                    <button onClick={handleLogout} className="dropdown-item logout-item">
                      <LogOut size={16} />
                      {t.logout}
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <Link to="/login" className="nav-btn">
                <User size={22} />
              </Link>
            )}

            <button
              className="nav-btn mobile-menu-btn"
              onClick={() => setShowMobileMenu(!showMobileMenu)}
            >
              {showMobileMenu ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile Menu */}
      {showMobileMenu && (
        <div className="mobile-menu-overlay" onClick={() => setShowMobileMenu(false)}>
          <div className="mobile-menu" onClick={e => e.stopPropagation()}>
            <Link to="/" className={`mobile-link ${isActive('/') ? 'active' : ''}`}>{t.home}</Link>
            <Link to="/products" className={`mobile-link ${isActive('/products') ? 'active' : ''}`}>{t.shop}</Link>
            <Link to="/cart" className="mobile-link">{t.cart} {cartCount > 0 && `(${cartCount})`}</Link>
            {user ? (
              <>
                <Link to="/profile" className="mobile-link">{t.profile}</Link>
                <Link to="/orders" className="mobile-link">{t.myOrders}</Link>
                <Link to="/settings" className="mobile-link">{t.settings}</Link>
                {user.role === 'admin' && <Link to="/admin" className="mobile-link">{t.adminPanel}</Link>}
                <button className="mobile-link mobile-logout" onClick={handleLogout}>{t.logout}</button>
              </>
            ) : (
              <Link to="/login" className="mobile-link">{t.login}</Link>
            )}
          </div>
        </div>
      )}
    </>
  );
};

export default Navbar;
